const raw = $json.data || "";

const lines = raw
  .split("\n")
  .map(line => line.trim())
  .filter(line => line.startsWith("data: "));

const events = [];

for (const line of lines) {
  const jsonStr = line.replace(/^data:\s*/, "").trim();

  // ignora linhas que não são JSON, como ping vazio
  if (!jsonStr.startsWith("{")) continue;

  try {
    events.push(JSON.parse(jsonStr));
  } catch (e) {
    // ignora linhas quebradas
  }
}

const workflowFinished = events.find(e => e.event === "workflow_finished");
const answerNodeFinished = events.find(
  e => e.event === "node_finished" &&
       e.data &&
       e.data.node_id === "answer"
);

const messageChunks = events
  .filter(e => e.event === "message" && typeof e.answer === "string")
  .map(e => e.answer);

const finalAnswer =
  workflowFinished?.data?.outputs?.answer ||
  answerNodeFinished?.data?.outputs?.answer ||
  messageChunks.join("").trim() ||
  "";

const conversationId =
  workflowFinished?.conversation_id ||
  answerNodeFinished?.conversation_id ||
  events.find(e => e.conversation_id)?.conversation_id ||
  "";

const messageId =
  workflowFinished?.message_id ||
  answerNodeFinished?.message_id ||
  events.find(e => e.message_id)?.message_id ||
  "";

return [
  {
    json: {
      answer: finalAnswer,
      conversation_id: conversationId,
      message_id: messageId,
      raw_events_count: events.length
    }
  }
];

const TIMEZONE = 'America/Sao_Paulo';
const MIN_DIFF_MINUTES = 240;

// Se vier de um único item com array dentro, usa ele.
// Se vier item por item, também funciona.
let rawSlots = [];

if (items.length === 1 && Array.isArray(items[0].json)) {
  rawSlots = items[0].json;
} else if (items.length === 1 && Array.isArray(items[0].json.slots)) {
  rawSlots = items[0].json.slots;
} else {
  rawSlots = items.map(item => item.json);
}

function getShift(hour) {
  if (hour < 12) return 'manha';
  if (hour < 18) return 'tarde';
  return 'noite';
}

function formatHour(hour, minute) {
  if (minute === 0) {
    return `${hour}h`;
  }

  return `${hour}h${String(minute).padStart(2, '0')}`;
}

function getLocalParts(utcString, timeZone = TIMEZONE) {
  const date = new Date(utcString);

  const formatter = new Intl.DateTimeFormat('pt-BR', {
    timeZone,
    weekday: 'long',
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
    hour12: false,
  });

  const parts = formatter.formatToParts(date);
  const get = (type) => parts.find(p => p.type === type)?.value || '';

  const weekdayRaw = get('weekday').toLowerCase();
  const weekday = weekdayRaw
    .replace('-feira', '')
    .replace('terca', 'terça')
    .replace('sabado', 'sábado');

  const day = get('day');
  const month = get('month');
  const year = get('year');
  const hour = Number(get('hour'));
  const minute = Number(get('minute'));

  const hourFormatted = formatHour(hour, minute);

  return {
    weekday,
    day,
    month,
    year,
    hour,
    minute,
    display: `${weekday}, ${day}/${month} às ${hourFormatted}`,
    shortDisplay: `${weekday} às ${hourFormatted}`,
    shift: getShift(hour),
  };
}


function getMinutesDiff(utcA, utcB) {
  const a = new Date(utcA).getTime();
  const b = new Date(utcB).getTime();
  return Math.abs((b - a) / 1000 / 60);
}

