const referenceYear = 2026;

function isFilled(value) {
  if (value === undefined || value === null) return false;
  if (typeof value === "string" && value.trim() === "") return false;
  return true;
}

function pick(primary, fallback = "", finalFallback = "") {
  if (isFilled(primary)) return primary;
  if (isFilled(fallback)) return fallback;
  return finalFallback;
}

function cleanText(value) {
  if (value === undefined || value === null) return "";
  return String(value)
    .replace(/\r\n/g, " ")
    .replace(/\n/g, " ")
    .replace(/\r/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function cleanEmail(value) {
  return cleanText(value).toLowerCase();
}

function normalizeNullableString(value) {
  return isFilled(value) ? cleanText(value) : "";
}

function normalizeRetryCount(value, fallback = 0) {
  const num = Number(value);
  return Number.isFinite(num) ? num : fallback;
}

function normalizeBrazilianDateTime(value, year = referenceYear) {
  if (!value || typeof value !== "string") return "";

  const text = value.trim().toLowerCase();

  // já está em ISO local correto
  if (/^\d{4}-\d{2}-\d{2}t\d{2}:\d{2}:\d{2}$/.test(text)) {
    return text.replace("t", "T");
  }

  // formatos aceitos:
  // 16/03 às 14h
  // 17/03 às 10h30
  // 16/03 14:00
  // 17/03 10h30
  // 16/03 as 14h
  const match = text.match(/(\d{1,2})\/(\d{1,2})(?:\s*(?:às|as)?\s*)(\d{1,2})(?:[:h](\d{2}))?/i);

  if (!match) return "";

  const [, dd, mm, hh, min] = match;

  const day = String(dd).padStart(2, "0");
  const month = String(mm).padStart(2, "0");
  const hour = String(hh).padStart(2, "0");
  const minute = String(min || "00").padStart(2, "0");

  return `${year}-${month}-${day}T${hour}:${minute}:00`;
}

